### 修正対象 [`scripts/fugue-execute.mjs`](/Users/masayuki/.claude/skills/orchestra-delegator/scripts/fugue-execute.mjs) ### 修正内容（diff形式） ```diff diff --git a/skills/orchestra-delegator/scripts/fugue-execute.mjs b/skills/orchestra-delegator/scripts/fugue-execute.mjs index 549f4fb4..c98eef36 100644 --- a/skills/orchestra-delegator/scripts/fugue-execute.mjs +++ b/skills/orchestra-delegator/scripts/fugue-execute.mjs @@ -169,6 +169,14 @@ function classify(task) { }; } +function isImplementationTask(task) { + return !/ (review|analysis|analyze|investigate|inspect|explain) /i.test(String(task || "")); +} + +function detectUiTask(task) { + return /(\.tsx|\.jsx|react component|ui component|design|layout|css|styled-component|tailwind)/i.test(String(task || "")); +} + function buildRequirementsPacket(task, meta) { return { objective: task, @@ -406,7 +414,10 @@ function simulationMatrix(runState, planText) { } function implementationMatrix(runState, feedback = "") { - const task = `Implement: ${runState.task}
Requirements:
${JSON.stringify(runState.requirementsPacket, null, 2)}
${feedback}`.trim(); + const guard = runState.uiTask + ? "IMPORTANT: This is a UI task. Use Pencil MCP for design work. Do not generate raw .tsx/.jsx files directly.
" + : ""; + const task = `${guard}Implement: ${runState.task}
Requirements:
${JSON.stringify(runState.requirementsPacket, null, 2)}
${feedback}`.trim(); if (runState.tier <= 1) return { lane: "codex:implementer", task }; if (runState.tier === 2) { return { @@ -593,11 +604,14 @@ function buildInitialState(args) { const id = runId(); const meta = classify(args.task); const tier = detectTier(args.task, args.tier); + const uiTask = detectUiTask(args.task) && isImplementationTask(args.task); + if (uiTask) console.error("UI task detected - Pencil MCP guidance injected"); return { runId: id, task: args.task, project: args.project || process.cwd(), tier, + uiTask, phase: tier >= 2 ? "awaiting_approval" : "implementation", requirementsPacket: buildRequirementsPacket(args.task, meta), planResult: null, ``` 前提: `review/analysis` 判定は明示キーワードベースで最小実装に留めました。より厳密なタスク種別判定は未実施です。 ### 検証結果 `node --check scripts/fugue-execute.mjs` を実行し、構文エラーなしを確認しました。
